INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-07460', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '內政部於2004年底頒訂「高風險家庭關懷輔導處遇實施計畫」，針對該計畫的敘述，下列何者為錯誤？', '["期待透過此計畫，及早發現高風險家庭的存在，並對家庭成員可能發生的身心或社會問題提供協助", "此計畫界定的家庭高風險因素包括：家庭成員關係紊亂或家庭衝突、家中兒童少年父母或主要照顧者 有精神疾病、酒藥癮且未持續就醫、家中兒童少年父母或主要照顧者有自殺風險、具有貧困、單親、 隔代教養等不利兒少成長之因素、非自願性失業會重複失業者、負擔家計者死亡、出走、重病或入獄 服刑者等", "此計畫最主要的關注焦點是高風險家庭中失去功能的主要照顧者，社會工作者需要進行家庭重建服務", "此計畫主要處遇的原則，是社會工作者協助連結得以降低或消除家庭高風險因素之社會資源"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07461', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在矯治社會工作的實務範疇中，針對犯罪矯治有「機構處遇」與「社區處遇」二種方式，下列針對社區 處遇的敘述，何者為錯誤？', '["社區處遇又稱為非機構式處遇，即將犯罪者不納入監獄等拘禁圍牆之內，而讓犯罪者仍然在自由社會 中生活，並藉由專業人員的輔導與訓練，至其完全適應社會規範為止", "社區處遇包括中途之家、寄養家庭、觀護、監外就業、假釋、保護管束、更生保護等方式", "社區處遇具有擴大人道主義處遇措施的運用、增進受刑人重返正常社會的可能性、節省國家公帑、減 少監禁處遇對受刑人的不良影響與促進預防再犯的效果等利益", "相較於青少年，較多成年人具有負擔家庭生活的重擔，透過社區處遇的方式，能使成年人早日回歸社 會，是比機構處遇更適合成年人的犯罪矯治方式"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07462', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在社會工作各個實務領域中，社會工作者都有機會與其他專業人員共同合作，並組成「跨專業團隊」。 跨專業團隊由不同訓練及不同專業的人所組成，是一項要求高度內部合作的工作。下列關於跨專業團隊 的敘述，何者為錯誤？', '["跨專業團隊運作中，通常會受到專業人員位階與權力差異的影響", "透過跨專業團隊的運作，專業得以有機會學習其他專業的介入技巧", "跨專業團隊永遠知道什麼是服務對象的最佳介入方式", "跨專業團隊要能有效運作，團隊成員瞭解彼此的角色與功能，是重要的因素之一"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07463', 'social-worker', 'social-worker-moex-100-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '鼓勵居民一人一信灌爆決策官員電子信箱，以表達主張爭取社區權益，屬於下列那一種社區工作模式的 策略？', '["社會計畫", "社會衝突", "社區發展", "社會行動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "4a84634809c5", "answer_pdf_sha1": "a5123f6d0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07464', 'social-worker', 'social-worker-moex-100-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對於校園霸凌問題，下列那一項工作不適宜由學校社工執行？', '["訂定校園霸凌事件處理流程及建立機制", "辦理防制霸凌教育宣導活動", "定期參加校務會議，建議改善防制措施及機制運作", "連結法律資源，協助受害學生尋求司法程序保障權益"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "4a84634809c5", "answer_pdf_sha1": "a5123f6d0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07465', 'social-worker', 'social-worker-moex-100-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會團體工作要考慮團體及成員組成的因素，就如同社區工作要進行的社區分析因素一樣，兩者要考慮 的因素有其類似性，但是下列那一項是社會團體工作不需要考慮的因素？', '["社區社會經濟特性", "社區內壓迫與歧視", "社區權力結構", "社區資源"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "4a84634809c5", "answer_pdf_sha1": "a5123f6d0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 3, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07466', 'social-worker', 'social-worker-moex-100-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列那一個議題，適合異質性團體？', '["婚姻中的第三者", "假性單親者的情感需求", "跨國婚姻的生活適應", "同性婚姻的親密關係"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "4a84634809c5", "answer_pdf_sha1": "a5123f6d0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 4, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07467', 'social-worker', 'social-worker-moex-100-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體工作者可善用面質技巧促進團體運作，面質技巧不適用於下列何種團體行為之成員？', '["成員有言行不一之矛盾行為", "成員對於別人的分享都會情緒易感，眼眶泛紅", "成員在團體中始終沒有說話", "成員對於別人的建議都會說「建議很好，可是現實中很難做到」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "4a84634809c5", "answer_pdf_sha1": "a5123f6d0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07468', 'social-worker', 'social-worker-moex-100-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列團體，何者不一定需要協同領導？', '["實習生所帶領的兒童成長團體", "社工員所帶領的夫妻衝突解決技巧學習團體", "精神醫療社工員所帶領的住院成人精障者之人際互動團體", "病友協會社工員所帶領的病友支持互助團體"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "4a84634809c5", "answer_pdf_sha1": "a5123f6d0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07469', 'social-worker', 'social-worker-moex-100-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者不是家庭治療的途徑（approach）？', '["家庭溝通模式", "家庭互動模式", "家庭結構系統模式", "家庭功能模式"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "4a84634809c5", "answer_pdf_sha1": "a5123f6d0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 7, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
